// Offscreen replay → PNG poster. Renders through the same WebGL engine the
// screen uses, so the export pixel-matches the live canvas rendering.

import { PaintEngine } from "@/engine/paint";
import type { FullStroke } from "./protocol";

const EXPORT_W = 1536;
const EXPORT_H = 1920; // matches the 4:5 paper aspect

export async function renderPosterPNG(
  strokes: FullStroke[],
  localAuthor: string,
): Promise<Blob> {
  const canvas = document.createElement("canvas");
  // PaintEngine sizes itself from clientWidth/Height * dpr (capped at 2);
  // park the canvas offscreen at the export size so the math holds
  canvas.style.position = "fixed";
  canvas.style.left = "-10000px";
  canvas.style.width = `${EXPORT_W / Math.min(2, window.devicePixelRatio || 1)}px`;
  canvas.style.height = `${EXPORT_H / Math.min(2, window.devicePixelRatio || 1)}px`;
  document.body.appendChild(canvas);
  const engine = new PaintEngine(canvas);
  try {
    engine.localAuthor = localAuthor;
    engine.setReveal(1); // everything visible in the poster
    engine.load(strokes);
    return await engine.exportPNG();
  } finally {
    engine.destroy();
    canvas.remove();
  }
}

export function downloadBlob(blob: Blob, filename: string) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.click();
  setTimeout(() => URL.revokeObjectURL(url), 5000);
}
